     1→// Optimized world-space slice shader with multi-resolution performance improvements
     2→// Key optimizations:
     3→// - Early exit for transparent regions
     4→// - LOD-based sampling for better cache coherence
     5→// - Vectorized bounds checking
     6→// - Reduced branching in sampling paths
     7→
     8→// --- Frame Uniform Buffer Object (UBO) ---
     9→struct FrameUbo {
    10→    origin_mm : vec4<f32>,   // World position at NDC (0,0) (homogeneous, w = 1)
    11→    u_mm      : vec4<f32>,   // World vector for NDC [0,1] in X direction
    12→    v_mm      : vec4<f32>,   // World vector for NDC [0,1] in Y direction
    13→    target_dim: vec2<u32>,   // Dimensions of the render target
    14→    _padding  : vec2<u32>,   // Padding to maintain 16-byte alignment
    15→};
    16→
    17→// --- Crosshair UBO ---
    18→struct CrosshairUbo {
    19→    world_position: vec3<f32>,
    20→    show_crosshair: u32,     // 0 = hide, 1 = show
    21→};
    22→
    23→// --- Per-Layer Storage Buffer ---
    24→struct LayerData {
    25→    // --- 16-byte aligned types first ---
    26→    world_to_voxel : mat4x4<f32>,      // Transform from world to voxel space
    27→    
